// ============================================================
// src/components/ResultScreen.jsx
// Shows round result, scores, and next-round / game-over state
// ============================================================
import React, { useEffect } from "react";
import socket from "../socket";

export default function ResultScreen({ game, player, result, onNextRound, onGameOver }) {
  const isHost = game && player && game.hostId === player._id;

  useEffect(() => {
    // Host will emit nextRound via button; non-hosts listen
    socket.on("roundStarted", () => onNextRound());
    return () => socket.off("roundStarted");
  }, [onNextRound]);

  const handleNextRound = () => {
    socket.emit("nextRound", { code: game.code });
  };

  return (
    <div className="screen">
      <header className="topbar">
        <span className="logo-sm">IMPOSTOR<span>·X</span></span>
        <span className="round-badge">
          {result.gameOver ? "GAME OVER" : `Round ${result.round} Result`}
        </span>
      </header>

      <div className="result-layout">
        {/* Outcome banner */}
        <div className={`outcome-banner ${result.impostorCaught ? "caught" : "escaped"}`}>
          {result.impostorCaught ? (
            <>
              <span className="outcome-icon">🎉</span>
              <div>
                <h2>Impostor Caught!</h2>
                <p><strong>{result.impostorName}</strong> was the impostor. The word was <strong>"{result.word}"</strong>.</p>
              </div>
            </>
          ) : (
            <>
              <span className="outcome-icon">🕵️</span>
              <div>
                <h2>Impostor Escaped!</h2>
                <p><strong>{result.impostorName}</strong> fooled everyone. The word was <strong>"{result.word}"</strong>.</p>
              </div>
            </>
          )}
        </div>

        {/* Descriptions reveal */}
        <div className="card">
          <h3 className="section-lbl">📋 All Descriptions</h3>
          <ul className="desc-list">
            {result.descriptions.map((d, i) => (
              <li key={i} className="desc-item">
                <span className="desc-author">{d.name}</span>
                <span className="desc-text">"{d.text}"</span>
              </li>
            ))}
          </ul>
        </div>

        {/* Scoreboard */}
        <div className="card">
          <h3 className="section-lbl">🏆 Scoreboard</h3>
          <ul className="score-list">
            {[...result.scores]
              .sort((a, b) => b.score - a.score)
              .map((p, i) => (
                <li key={i} className="score-item">
                  <span className="rank">#{i + 1}</span>
                  <span className="av sm">{p.name[0].toUpperCase()}</span>
                  <span className="score-name">
                    {p.name}
                    {p.isImpostor && <span className="imp-badge">IMPOSTOR</span>}
                  </span>
                  <span className="score-pts">{p.score} pts</span>
                </li>
              ))}
          </ul>
        </div>

        {/* Game over or next round */}
        {result.gameOver ? (
          <div className="card center">
            <h2 className={result.winner === "crewmates" ? "win-crew" : "win-imp"}>
              {result.winner === "crewmates" ? "🎉 Crewmates Win!" : "🕵️ Impostor Wins!"}
            </h2>
            <button className="btn primary" onClick={onGameOver}>Play Again</button>
          </div>
        ) : (
          <div className="card center">
            {isHost ? (
              <button className="btn primary" onClick={handleNextRound}>
                ▶ Start Round {result.nextRound}
              </button>
            ) : (
              <p className="wait-msg">⏳ Waiting for host to start next round…</p>
            )}
          </div>
        )}
      </div>
    </div>
  );
}
